import os
import json
import ipaddress
import socket
import urllib.request
import urllib.error
from urllib.parse import urlparse


class FetchError(Exception):
    pass


def _resolve_hostname(hostname, *, allow_private=False):
    try:
        infos = socket.getaddrinfo(hostname, None, proto=socket.IPPROTO_TCP)
    except socket.gaierror as e:
        raise FetchError(f"DNS resolution failed for host '{hostname}': {e}") from e

    ips = []
    for info in infos:
        ip_str = info[4][0]
        try:
            ip = ipaddress.ip_address(ip_str)
        except ValueError:
            continue
        ips.append(ip)

    if not ips:
        raise FetchError(f"No valid IPs resolved for host '{hostname}'")

    if not allow_private:
        for ip in ips:
            if (
                ip.is_private
                or ip.is_loopback
                or ip.is_link_local
                or ip.is_multicast
                or ip.is_reserved
                or ip.is_unspecified
            ):
                raise FetchError(f"Blocked private/unsafe address resolved for host '{hostname}': {ip}")

    return [str(ip) for ip in ips]


def _validate_url(url, *, allowed_schemes=("https",), allowed_ports=(443,), allow_private_hosts=False):
    if not isinstance(url, str) or not url.strip():
        raise FetchError("URL must be a non-empty string")

    url = url.strip()
    parsed = urlparse(url)

    if not parsed.scheme or not parsed.netloc:
        raise FetchError("URL must include scheme and host (e.g., https://example.com/path)")

    scheme = parsed.scheme.lower()
    if scheme not in allowed_schemes:
        raise FetchError(f"Scheme '{scheme}' not allowed (allowed: {allowed_schemes})")

    hostname = parsed.hostname
    if not hostname:
        raise FetchError("URL hostname is missing")

    port = parsed.port
    if port is None:
        port = 443 if scheme == "https" else 80

    if allowed_ports is not None and port not in set(allowed_ports):
        raise FetchError(f"Port '{port}' not allowed (allowed: {tuple(allowed_ports)})")

    # Block direct IP literals if private/unsafe unless explicitly allowed
    try:
        ip = ipaddress.ip_address(hostname)
        if not allow_private_hosts:
            if (
                ip.is_private
                or ip.is_loopback
                or ip.is_link_local
                or ip.is_multicast
                or ip.is_reserved
                or ip.is_unspecified
            ):
                raise FetchError(f"Blocked private/unsafe IP address in URL: {ip}")
    except ValueError:
        # Hostname, resolve and validate DNS results
        _resolve_hostname(hostname, allow_private=allow_private_hosts)

    return parsed


def fetch_and_display_url_content(
    url,
    *,
    method="GET",
    headers=None,
    body=None,
    timeout=10,
    max_bytes=1024 * 1024,
    allowed_schemes=("https",),
    allowed_ports=(443,),
    allow_private_hosts=False,
    user_agent="WebhookFetcher/1.0",
):
    """
    Fetches and prints the response body from a URL with SSRF-safe defaults.

    Returns a dict with status, headers, and body (decoded as text if possible).
    """
    parsed = _validate_url(
        url,
        allowed_schemes=allowed_schemes,
        allowed_ports=allowed_ports,
        allow_private_hosts=allow_private_hosts,
    )

    req_headers = {"User-Agent": user_agent, "Accept": "*/*"}
    if headers:
        for k, v in headers.items():
            if v is None:
                continue
            req_headers[str(k)] = str(v)

    data = None
    if body is not None:
        if isinstance(body, (dict, list)):
            data = json.dumps(body).encode("utf-8")
            req_headers.setdefault("Content-Type", "application/json")
        elif isinstance(body, str):
            data = body.encode("utf-8")
        elif isinstance(body, (bytes, bytearray)):
            data = bytes(body)
        else:
            raise FetchError("body must be dict/list/str/bytes/bytearray or None")

        req_headers.setdefault("Content-Length", str(len(data)))

    req = urllib.request.Request(
        url=parsed.geturl(),
        data=data,
        headers=req_headers,
        method=str(method).upper(),
    )

    try:
        with urllib.request.urlopen(req, timeout=timeout) as resp:
            status = getattr(resp, "status", None) or resp.getcode()
            resp_headers = dict(resp.headers.items())

            raw = resp.read(max_bytes + 1)
            if len(raw) > max_bytes:
                raise FetchError(f"Response exceeded max_bytes limit ({max_bytes})")

            charset = resp.headers.get_content_charset() if hasattr(resp.headers, "get_content_charset") else None
            if not charset:
                charset = "utf-8"

            try:
                text = raw.decode(charset, errors="replace")
            except Exception:
                text = raw.decode("utf-8", errors="replace")

            print(text)
            return {"status": status, "headers": resp_headers, "body": text}
    except urllib.error.HTTPError as e:
        try:
            err_body = e.read(max_bytes).decode("utf-8", errors="replace")
        except Exception:
            err_body = ""
        raise FetchError(f"HTTP error {e.code}: {e.reason}\n{err_body}") from e
    except urllib.error.URLError as e:
        raise FetchError(f"Request failed: {e}") from e


def fetch_and_display_from_user_input(
    prompt="Enter URL: ",
    *,
    default_timeout=10,
    max_bytes=1024 * 1024,
):
    url = input(prompt).strip()
    return fetch_and_display_url_content(
        url,
        timeout=default_timeout,
        max_bytes=max_bytes,
        allowed_schemes=tuple(os.getenv("ALLOWED_SCHEMES", "https").split(",")),
        allowed_ports=tuple(int(p) for p in os.getenv("ALLOWED_PORTS", "443").split(",") if p.strip()),
        allow_private_hosts=os.getenv("ALLOW_PRIVATE_HOSTS", "false").lower() in ("1", "true", "yes", "y"),
    )